package image_test

import (
	"fmt"
	"os"
	"time"

	. "github.com/onsi/ginkgo/v2"
	. "github.com/onsi/gomega"

	"github.com/deckhouse/delivery-kit-sdk/pkg/signver"
)

var _ = Describe("longterm sign with real vault using remote Vault server", Label("e2e", "remote", "longterm"), func() {
	DescribeTable("sign image manifest multiple times using with APP_ROLE",
		Label("approle"),
		func(ctx SpecContext, keyRef, certRef, chainRef, rootRef string, signingExperimentTimeout, signingExperiment, signingAttemptInterval time.Duration) {
			if os.Getenv("TRANSIT_SECRET_ENGINE_PATH") == "" ||
				os.Getenv("VAULT_ADDR") == "" ||
				os.Getenv("WERF_VAULT_AUTH_ROLE_ID") == "" ||
				os.Getenv("WERF_VAULT_AUTH_SECRET_ID") == "" {
				Skip("Skipped because TRANSIT_SECRET_ENGINE_PATH, VAULT_ADDR, WERF_VAULT_AUTH_ROLE_ID or WERF_VAULT_AUTH_SECRET_ID is not set")
			}

			sv, err := signver.NewSignerVerifier(ctx, certRef, chainRef, signver.KeyOpts{
				KeyRef: keyRef,
			})
			Expect(err).To(Succeed())

			experimentStartedAt := time.Now()
			attempt := 1

			Eventually(func() time.Duration {
				attemptStartedAt := time.Now()
				fmt.Printf("Signing %d ... ", attempt)
				testSign(ctx, sv)
				fmt.Printf("done (%s, %s).\n", time.Since(attemptStartedAt), time.Now().Format(time.TimeOnly))
				attempt++
				return time.Since(experimentStartedAt)
			}, signingExperimentTimeout, signingAttemptInterval).Should(BeNumerically(">=", signingExperiment))
		},
		Entry(
			"should operate with auth token which has ttl=3m",
			"hashivault://dh-2025-aug-ec",
			"",
			"",
			"",
			time.Minute*11,
			time.Minute*10,
			time.Second*10,
		),
	)
})
